}

/* --- Traces View --- */
.traces-view {
  display: grid;
  grid-template-columns: 1fr 280px;
  gap: 16px;
  flex: 1;
}

.topology-graph {
  position: relative;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  min-height: 400px;
  padding: 20px;
}

.tnode {
  position: absolute;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 12px 16px;
  cursor: pointer;
  transition: all var(--transition);
  min-width: 100px;
  text-align: center;
}

.tnode:hover {
  border-color: var(--border-bright);
  box-shadow: var(--shadow-hover);
}

.tnode.selected {
  box-shadow: 0 0 0 3px var(--gold-soft);
}

.tnode-header {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  margin-bottom: 4px;
}

.tnode-emoji {
  font-size: 16px;
}

.tnode-label {
  font-size: 12px;
  font-weight: 700;
  color: var(--text-bright);
}

.tnode-count {
  font-size: 18px;
  font-weight: 800;
  font-variant-numeric: tabular-nums;
}

/* --- Traces Detail Panel --- */
.traces-detail {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.detail-header h3 {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-bright);
  display: flex;
  align-items: center;
  gap: 8px;
}

